"use strict";(globalThis.webpackChunklearnalgorithms=globalThis.webpackChunklearnalgorithms||[]).push([[1631],{9124(a){a.exports=JSON.parse('{"tag":{"label":"State Space Search","permalink":"/concepts/tags/state-space-search","allTagsPath":"/concepts/tags","count":2,"items":[{"id":"state-space-search-and-optimization/backtracking","title":"Backtracking","description":"In algorithm design, brute force or exhaustive search should not be used unless absolutely necessary. To understand why, consider a classic combinatorial puzzle: the Magic Square. This puzzle presents an $n \\\\times n$ table to be filled with $n^2$ distinct integers ranging from 1 to $n^2$. The objective is to arrange the numbers such that the sum of each individual row, column, and corner-to-corner diagonal matches exactly.","permalink":"/concepts/state-space-search-and-optimization/backtracking"},{"id":"state-space-search-and-optimization/branch-and-bound","title":"Branch and Bound","description":"When solving hard combinatorial problems, Backtracking provides an exact solution by executing a systematic Depth-First Search (DFS). However, it does so blindly, relying entirely on hitting an unfeasible boundary before turning around.","permalink":"/concepts/state-space-search-and-optimization/branch-and-bound"}],"unlisted":false}}')}}]);